func seek(target_pos: Vector2) -> Vector2:
    var desired = (target_pos - global_position).normalized() * max_speed
    return desired - velocity

func flee(threat_pos: Vector2) -> Vector2:
    var desired = (global_position - threat_pos).normalized() * max_speed
    return desired - velocity

func arrive(target_pos: Vector2) -> Vector2:
    var to_target = target_pos - global_position
    var dist = to_target.length()
    var speed = max_speed if dist > slowing_radius else max_speed * (dist / slowing_radius)
    var desired = to_target.normalized() * speed
    return desired - velocity

var wander_angle: float = 0.0
func wander() -> Vector2:
    wander_angle += randf_range(-wander_jitter, wander_jitter)
    var circle_center = velocity.normalized() * wander_radius
    var displacement = Vector2.from_angle(wander_angle) * wander_distance
    return seek(global_position + circle_center + displacement)

func pursue(target: Node2D) -> Vector2:
    var look_ahead = target.velocity.length() / max_speed
    var future_pos = target.global_position + target.velocity * look_ahead
    return seek(future_pos)

func evade(pursuer: Node2D) -> Vector2:
    var look_ahead = pursuer.velocity.length() / max_speed
    var future_pos = pursuer.global_position + pursuer.velocity * look_ahead
    return flee(future_pos)

func avoid_obstacles() -> Vector2:
    var ray = PhysicsRayQueryParameters2D.create(global_position,
        global_position + velocity.normalized() * detection_range, obstacle_mask)
    var result = get_world_2d().direct_space_state.intersect_ray(ray)
    if result:
        var avoid_dir = result.normal.rotated(PI / 2)
        return avoid_dir * max_speed
    return Vector2.ZERO

func compute_steering() -> Vector2:
    var force = Vector2.ZERO
    force += seek(target.global_position) * seek_weight
    force += avoid_obstacles() * avoid_weight
    force += separation(neighbors) * separation_weight
    return force.limit_length(max_force)

func separation(neighbors: Array) -> Vector2:
    var steer = Vector2.ZERO
    for n in neighbors:
        var d = global_position.distance_to(n.global_position)
        if d < separation_radius and d > 0:
            steer += (global_position - n.global_position).normalized() / d
    return steer

func alignment(neighbors: Array) -> Vector2:
    var avg_vel = Vector2.ZERO
    for n in neighbors: avg_vel += n.velocity
    if neighbors.size() > 0: avg_vel /= neighbors.size()
    return avg_vel - velocity

func cohesion(neighbors: Array) -> Vector2:
    var center = Vector2.ZERO
    for n in neighbors: center += n.global_position
    if neighbors.size() > 0: center /= neighbors.size()
    return seek(center)

